## Common patterns

### Search with live filtering

Display results that update as the user types:

```jsx-live-dev
const App = () => {
  const [query, setQuery] = useState<string>('');

  const products = [
    'Laptop', 'Phone', 'Tablet', 'Monitor', 'Keyboard',
    'Mouse', 'Headphones', 'Camera', 'Printer', 'Scanner'
  ];

  const filteredProducts = products.filter(product =>
    product.toLowerCase().includes(query.toLowerCase())
  );

  return (
    <Stack direction="column" gap="400">
      <SearchInput
        value={query}
        onChange={setQuery}
        placeholder="Search products..."
      />
      <Stack direction="column" gap="200">
        {query && filteredProducts.length === 0 && (
          <Text fontSize="sm" color="neutral.11">
            No results found for "{query}"
          </Text>
        )}
        {query && filteredProducts.length > 0 && (
          <Text fontSize="sm" fontWeight="medium">
            Found {filteredProducts.length} result{filteredProducts.length !== 1 ? 's' : ''}:
          </Text>
        )}
        {query && filteredProducts.map(product => (
          <Text key={product} fontSize="sm">
            • {product}
          </Text>
        ))}
      </Stack>
    </Stack>
  );
}
```

### Search with submit action

Handle search submission with Enter key or button click:

```jsx-live-dev
const App = () => {
  const [query, setQuery] = useState<string>('');
  const [results, setResults] = useState<string[]>([]);
  const [isSearching, setIsSearching] = useState<boolean>(false);

  const performSearch = (searchQuery: string) => {
    if (!searchQuery.trim()) {
      setResults([]);
      return;
    }

    setIsSearching(true);

    // Simulate API call delay
    setTimeout(() => {
      const mockResults = [
        `Result 1 for "${searchQuery}"`,
        `Result 2 for "${searchQuery}"`,
        `Result 3 for "${searchQuery}"`,
      ];
      setResults(mockResults);
      setIsSearching(false);
    }, 500);
  };

  return (
    <Stack direction="column" gap="400">
      <Stack direction="row" gap="200" alignItems="center">
        <SearchInput
          value={query}
          onChange={setQuery}
          onSubmit={performSearch}
          placeholder="Type and press Enter..."
        />
        <Button
          onClick={() => performSearch(query)}
          size="md"
        >
          Search
        </Button>
      </Stack>

      {isSearching && (
        <Text fontSize="sm" color="neutral.11">
          Searching...
        </Text>
      )}

      {!isSearching && results.length > 0 && (
        <Stack direction="column" gap="200">
          <Text fontSize="sm" fontWeight="medium">
            Search Results:
          </Text>
          {results.map((result, index) => (
            <Text key={index} fontSize="sm">
              • {result}
            </Text>
          ))}
        </Stack>
      )}
    </Stack>
  );
}
```

## Testing your implementation

These examples demonstrate how to test your implementation when using SearchInput within your application. As the component's internal functionality is already tested by Nimbus, these patterns help you verify your integration and application-specific logic.

### Basic Rendering Tests

Verify the component renders with expected elements

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { SearchInput, NimbusProvider } from "@commercetools/nimbus";

describe("SearchInput - Basic rendering", () => {
  it("renders search input with search icon", () => {
    render(
      <NimbusProvider>
        <SearchInput placeholder="Search..." aria-label="Search" />
      </NimbusProvider>
    );

    const searchBox = screen.getByRole("searchbox");
    expect(searchBox).toBeInTheDocument();
    expect(searchBox).toHaveAttribute("type", "search");
    expect(searchBox).toHaveAttribute("placeholder", "Search...");
  });

  it("renders with clear button (hidden when empty)", () => {
    render(
      <NimbusProvider>
        <SearchInput placeholder="Search..." aria-label="Search" />
      </NimbusProvider>
    );

    // Clear button is always in DOM
    const clearButton = screen.getByRole("button", { hidden: true });
    expect(clearButton).toBeInTheDocument();

    // But hidden visually when empty
    const computedStyle = window.getComputedStyle(clearButton);
    expect(computedStyle.opacity).toBe("0");
    expect(computedStyle.pointerEvents).toBe("none");
  });
});
```

### Interaction Tests

Test user interactions with the search input

```tsx
import { describe, it, expect, vi } from "vitest";
import { render, screen, waitFor } from "@testing-library/react";
import userEvent from "@testing-library/user-event";
import { SearchInput, NimbusProvider } from "@commercetools/nimbus";

describe("SearchInput - Interactions", () => {
  it("handles typing in search input", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <SearchInput placeholder="Search..." aria-label="Search" />
      </NimbusProvider>
    );

    const searchBox = screen.getByRole("searchbox");
    await user.type(searchBox, "test query");

    expect(searchBox).toHaveValue("test query");
  });

  it("calls onChange with string value on input", async () => {
    const user = userEvent.setup();
    const handleChange = vi.fn();

    render(
      <NimbusProvider>
        <SearchInput
          onChange={handleChange}
          placeholder="Search..."
          aria-label="Search"
        />
      </NimbusProvider>
    );

    const searchBox = screen.getByRole("searchbox");
    await user.type(searchBox, "test");

    // onChange receives string, not event
    expect(handleChange).toHaveBeenCalledWith("test");
  });

  it("shows clear button when input has value", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <SearchInput placeholder="Search..." aria-label="Search" />
      </NimbusProvider>
    );

    const searchBox = screen.getByRole("searchbox");
    await user.type(searchBox, "test");

    const clearButton = screen.getByRole("button");

    await waitFor(() => {
      const computedStyle = window.getComputedStyle(clearButton);
      expect(computedStyle.opacity).toBe("1");
      expect(computedStyle.pointerEvents).toBe("auto");
    });
  });

  it("clears input when clear button is clicked", async () => {
    const user = userEvent.setup();
    render(
      <NimbusProvider>
        <SearchInput placeholder="Search..." aria-label="Search" />
      </NimbusProvider>
    );

    const searchBox = screen.getByRole("searchbox");
    await user.type(searchBox, "test query");
    expect(searchBox).toHaveValue("test query");

    const clearButton = screen.getByRole("button");
    await user.click(clearButton);

    expect(searchBox).toHaveValue("");
  });

  it("calls onClear when clear button is clicked", async () => {
    const user = userEvent.setup();
    const handleClear = vi.fn();

    render(
      <NimbusProvider>
        <SearchInput
          defaultValue="test"
          onClear={handleClear}
          placeholder="Search..."
          aria-label="Search"
        />
      </NimbusProvider>
    );

    const clearButton = screen.getByRole("button");
    await user.click(clearButton);

    expect(handleClear).toHaveBeenCalled();
  });
});
```

